// src/hooks/useNotification.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from '../types/NotificationElement';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface UseNotificationReturn {
  notify: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

const useNotification = (): UseNotificationReturn => {
  const notificationElem = useContext(NotificationContext);
  const [element, setElement] = useState<HTMLHuelNotificationElement | null>(notificationElem);

  useEffect(() => {
    setElement(notificationElem);
  }, [notificationElem]);

  const notify = async (props: NotificationProps) => {
    if (!element) return;

    const { heading, subheading, type } = props;
    await element.open({
      heading,
      subheading,
      type,
    });
  };

  return { notify };
};

export default useNotification;
